/* =============================================
   ESTADO GLOBAL
============================================= */
var carrito = []; // Se rehidratará en DOMContentLoaded
var usuario = JSON.parse(localStorage.getItem('stellaris_usuario') || 'null');


/* Rehidratar carrito desde localStorage — recupera img del producto en memoria */
function rehidratarCarrito() {
  var guardado = JSON.parse(localStorage.getItem('stellaris_carrito') || '[]');
  carrito = guardado.map(function(item) {
    var p = productos.find(function(x){ return x.id === item.id; });
    return Object.assign({}, item, { img: p ? p.img : '' });
  });
}

/* =============================================
   BANNER CARRUSEL
============================================= */
let iBanner = 0;
function initBanner() {
  const pista = document.getElementById('pistaBanner');
  if(!pista) return;
  const total = pista.children.length;
  function moverBanner(n) { iBanner = (n + total) % total; pista.style.transform = `translateX(-${iBanner * 100}%)`; }
  window.bNext   = () => moverBanner(iBanner + 1);
  window.bBefore = () => moverBanner(iBanner - 1);
  setInterval(window.bNext, 3800);
}

/* =============================================
   CARRITO
============================================= */
function anadirCarrito(id, event) {
  if(event) event.stopPropagation();
  // Buscar tanto por string como por número para compatibilidad
  var p = productos.find(function(x){ return x.id === id || x.id === String(id); });
  if(!p) { console.warn('Producto no encontrado:', id); return; }
  var e = carrito.find(function(x){ return x.id === p.id; });
  if(e) e.cantidad++;
  else {
    // Solo guardar los campos necesarios (no la galería completa para no llenar localStorage)
    carrito.push({
      id: p.id, nombre: p.nombre, precio: p.precio,
      img: p.img, col: p.col, cat: p.cat, cantidad: 1
    });
  }
  guardarCarrito(); renderizarCarrito();
  toast('❖ "' + p.nombre + '" añadido al carrito');
}
function quitarCarrito(id) {
  var idx = carrito.findIndex(function(x){ return x.id === id || x.id === String(id); });
  if(idx < 0) return;
  if(carrito[idx].cantidad > 1) carrito[idx].cantidad--;
  else carrito.splice(idx, 1);
  guardarCarrito(); renderizarCarrito();
}
function guardarCarrito() {
  // Guardar solo los campos ligeros (sin img ni galeria base64)
  var ligero = carrito.map(function(item){
    return {id:item.id,nombre:item.nombre,precio:item.precio,col:item.col,cat:item.cat,cantidad:item.cantidad};
  });
  try { localStorage.setItem('stellaris_carrito', JSON.stringify(ligero)); } catch(e) { console.warn('localStorage lleno'); }
}
function renderizarCarrito() {
  var cont    = document.getElementById('carritoItems');
  var vacio   = document.getElementById('carritoVacio');
  var badge   = document.getElementById('badgeC');
  var totalEl = document.getElementById('carritoTotal');
  if (!cont || !badge || !totalEl) return;

  var total = carrito.reduce(function(s, i) { return s + i.precio * i.cantidad; }, 0);
  var uds   = carrito.reduce(function(s, i) { return s + i.cantidad; }, 0);
  badge.style.display = uds > 0 ? 'flex' : 'none';
  badge.textContent   = uds;
  totalEl.textContent = total.toLocaleString('es-ES') + ',00 \u20AC';
  if (vacio) vacio.style.display = carrito.length === 0 ? 'block' : 'none';

  // Eliminar items previos
  cont.querySelectorAll('.ca-item').forEach(function(x) { x.remove(); });

  carrito.forEach(function(item) {
    // Recuperar imagen desde productos si no está en el item
    if (!item.img) {
      var prod = typeof productos !== 'undefined'
        ? productos.find(function(p) { return p.id === item.id; })
        : null;
      if (prod) item.img = prod.img;
    }

    var d = document.createElement('div');
    d.className = 'ca-item';

    // Miniatura imagen
    var thumb = document.createElement('div');
    thumb.className = 'ca-emoji';
    thumb.style.cssText = 'padding:0;overflow:hidden;flex-shrink:0;width:60px;height:60px;background:var(--rosa-fondo)';
    if (item.img) {
      var img = document.createElement('img');
      img.src = item.img;
      img.alt = item.nombre;
      img.style.cssText = 'width:100%;height:100%;object-fit:cover';
      thumb.appendChild(img);
    }

    // Info
    var info = document.createElement('div');
    info.className = 'ca-info';
    info.innerHTML =
      '<div class="ca-nom">' + item.nombre + '</div>' +
      '<div class="ca-price">' + (item.precio * item.cantidad).toLocaleString('es-ES') + ',00 \u20AC</div>';

    // Controles cantidad
    var ctrl = document.createElement('div');
    ctrl.className = 'ca-ctrl';

    var btnMenos = document.createElement('button');
    btnMenos.className = 'btn-q';
    btnMenos.innerHTML = '&#8722;';
    btnMenos.addEventListener('click', function(e) {
      e.stopPropagation();
      quitarCarrito(item.id);
    });

    var span = document.createElement('span');
    span.style.cssText = 'font-size:.86rem;min-width:16px;text-align:center';
    span.textContent = item.cantidad;

    var btnMas = document.createElement('button');
    btnMas.className = 'btn-q';
    btnMas.textContent = '+';
    btnMas.addEventListener('click', function(e) {
      e.stopPropagation();
      anadirCarrito(item.id);
    });

    ctrl.appendChild(btnMenos);
    ctrl.appendChild(span);
    ctrl.appendChild(btnMas);

    d.appendChild(thumb);
    d.appendChild(info);
    d.appendChild(ctrl);
    cont.appendChild(d);
  });
}

function toggleCarrito() {
  const p = document.getElementById('panel-carrito');
  const o = document.getElementById('overlay');
  if(p.classList.contains('open')) { p.classList.remove('open'); o.classList.remove('on'); }
  else { cerrarModales(); p.classList.add('open'); o.classList.add('on'); }
}
function finalizarCompra() {
  if(carrito.length === 0) { toast('Tu carrito está vacío.'); return; }
  toast('✦ Gracias por tu pedido. Recibirás confirmación pronto.');
  carrito = []; guardarCarrito(); renderizarCarrito(); toggleCarrito();
}

/* =============================================
   MODALES
============================================= */
function abrirContacto(e) { if(e)e.preventDefault(); cerrarPanel(); document.getElementById('modal-contacto').classList.add('on'); document.getElementById('overlay').classList.add('on'); }
function abrirSesion()  { if(usuario){toast(`Sesión activa: ${usuario.nombre}`);return;} cerrarPanel(); document.getElementById('modal-sesion').classList.add('on'); document.getElementById('overlay').classList.add('on'); }
function abrirLegal(tab) { cerrarPanel(); document.getElementById('modal-legal').classList.add('on'); document.getElementById('overlay').classList.add('on'); if(tab) cambiarTabLegal(tab); }
function cerrarModales() { document.querySelectorAll('.modal').forEach(m=>m.classList.remove('on')); document.getElementById('overlay').classList.remove('on'); cerrarPanel(); document.body.style.overflow=''; }
function cerrarPanel()   { document.getElementById('panel-carrito').classList.remove('open'); }

/* ── Tabs legales ── */
function cambiarTabLegal(id) {
  document.querySelectorAll('.legal-tab').forEach(t=>t.classList.remove('on'));
  document.querySelectorAll('.legal-panel').forEach(p=>p.classList.remove('on'));
  document.querySelector(`.legal-tab[data-tab="${id}"]`)?.classList.add('on');
  document.getElementById('legal-' + id)?.classList.add('on');
}

/* ── Contacto ── */
function toggleEmailForm() { document.getElementById('fEmail').classList.toggle('vis'); document.getElementById('btnCorreo').classList.toggle('on'); }
function llamarAhora()  { toast('📞 Llamando al 690 968 481...'); window.location.href='tel:690968481'; }
function reservarCita() { toast('📅 Abriendo agenda de citas...'); }
function enviarForm() {
  const motivo = document.getElementById('motivo').value;
  const nombre = document.getElementById('nombreC').value.trim();
  const apell  = document.getElementById('apellidoC').value.trim();
  const email  = document.getElementById('emailC').value.trim();
  if(!motivo||!nombre||!apell||!email) { toast('Completa los campos obligatorios (*)'); return; }
  toast('✦ Consulta enviada. Te responderemos pronto.');
  document.getElementById('fEmail').classList.remove('vis');
  document.getElementById('btnCorreo').classList.remove('on');
  ['motivo','msgC','nombreC','apellidoC','emailC','telC'].forEach(id => { const el=document.getElementById(id); if(el)el.value=''; });
}

/* ── Sesión ── */
function iniciarSesion() {
  const email = document.getElementById('lEmail').value.trim();
  const pwd   = document.getElementById('lPwd').value;
  if(!email||!pwd) { toast('Introduce tu email y contraseña.'); return; }
  const usuarios = JSON.parse(localStorage.getItem('stellaris_usuarios') || '[]');
  const u = usuarios.find(x => x.email === email && x.password === pwd);
  if(!u) { toast('Credenciales incorrectas.'); return; }
  usuario = {nombre:u.nombre, email:u.email};
  localStorage.setItem('stellaris_usuario', JSON.stringify(usuario));
  actualizarUsr(); cerrarModales();
  toast(`✦ Bienvenida de nuevo, ${u.nombre}.`);
}
function crearCuenta() {
  const nombre = document.getElementById('rNombre').value.trim();
  const apell  = document.getElementById('rApellido').value.trim();
  const email  = document.getElementById('rEmail').value.trim();
  const pwd    = document.getElementById('rPwd').value;
  const conf   = document.getElementById('rConf').value;
  const privOk = document.getElementById('ckPrivacidad').checked;
  if(!nombre||!apell||!email||!pwd||!conf) { toast('Completa todos los campos obligatorios (*)'); return; }
  if(!privOk) { toast('Debes aceptar la Política de Privacidad para continuar.'); return; }
  if(pwd !== conf)   { toast('Las contraseñas no coinciden.'); return; }
  if(pwd.length < 6) { toast('La contraseña debe tener mínimo 6 caracteres.'); return; }
  const usuarios = JSON.parse(localStorage.getItem('stellaris_usuarios') || '[]');
  if(usuarios.find(u => u.email === email)) { toast('Ya existe una cuenta con este correo.'); return; }
  const publicidad = document.getElementById('ckPublicidad')?.checked || false;
  usuarios.push({nombre, apellido:apell, email, password:pwd, publicidad});
  localStorage.setItem('stellaris_usuarios', JSON.stringify(usuarios));
  usuario = {nombre, email};
  localStorage.setItem('stellaris_usuario', JSON.stringify(usuario));
  actualizarUsr(); cerrarModales();
  toast(`✦ Cuenta creada. Bienvenida, ${nombre}.`);
}
function olvidoPwd() {
  const email = document.getElementById('lEmail').value.trim();
  if(!email) { toast('Introduce tu correo para restablecer la contraseña.'); return; }
  toast('✦ Instrucciones enviadas a tu correo.');
}
function cerrarSesion() {
  usuario = null; localStorage.removeItem('stellaris_usuario');
  actualizarUsr(); toast('Sesión cerrada correctamente.');
}
function actualizarUsr() {
  const c = document.getElementById('estadoUsr');
  if(usuario) c.innerHTML = `<span>Hola, ${usuario.nombre}</span><button class="btn-logout" onclick="cerrarSesion()">Salir</button>`;
  else c.innerHTML = '';
}

/* ── Suscripción footer ── */
function suscribirFooter() {
  const v = document.getElementById('emailSus')?.value.trim();
  if(!v||!v.includes('@')) { toast('Introduce un correo válido.'); return; }
  toast('✦ ¡Gracias! Te has suscrito a Stellaris.');
  document.getElementById('emailSus').value = '';
}

/* =============================================
   TOAST
============================================= */
let timerToast;
function toast(msg) {
  const el = document.getElementById('toast');
  el.textContent = msg; el.classList.add('vis');
  clearTimeout(timerToast);
  timerToast = setTimeout(() => el.classList.remove('vis'), 3500);
}

/* ── Galería en detalle ── */
function initGaleria(id) {
  var p = productos.find(function(x){ return x.id === id; });
  if(!p || !p.galeria || p.galeria.length <= 1) return;
  var imgs = p.galeria;
  var actual = 0;
  var thumbs = document.getElementById('pd-thumbs-' + id);
  var mainImg = document.getElementById('pd-main-img-' + id);
  if(!thumbs || !mainImg) return;
  thumbs.innerHTML = '';
  imgs.forEach(function(src, i) {
    var t = document.createElement('div');
    t.className = 'pd-thumb' + (i===0?' activa':'');
    t.style.cssText = 'width:60px;height:60px;overflow:hidden;cursor:pointer;border:2px solid '+(i===0?'var(--negro)':'var(--gris-borde)')+';flex-shrink:0';
    var img = document.createElement('img');
    img.src = src;
    img.style.cssText = 'width:100%;height:100%;object-fit:cover';
    t.appendChild(img);
    t.onclick = function(){
      mainImg.src = src;
      actual = i;
      document.querySelectorAll('#pd-thumbs-'+id+' .pd-thumb').forEach(function(el,j){
        el.style.borderColor = j===i?'var(--negro)':'var(--gris-borde)';
      });
    };
    thumbs.appendChild(t);
  });
}
/* INDEX */

function rehidratarCarrito() {
  try {
    var guardado = JSON.parse(localStorage.getItem('stellaris_carrito') || '[]');
    carrito = guardado.map(function(item) {
      var prod = productos.find(function(p){ return p.id === item.id; });
      return { id:item.id, nombre:item.nombre, precio:item.precio,
               col:item.col, cat:item.cat, cantidad:item.cantidad,
               img: prod ? prod.img : null };
    });
  } catch(e) { carrito = []; }
}
document.addEventListener('DOMContentLoaded', function() {
  rehidratarCarrito();
  initBanner();
  rehidratarCarrito();
  renderizarCarrito();
  actualizarUsr();
  // Popup
  if(!sessionStorage.getItem('stellaris_popup')) {
    setTimeout(function() { document.getElementById('popup-overlay').style.display='flex'; }, 1200);
  }
  // Destacados
  var idsDestacados = ['rl1','ms1','collar1','pend1'];
  var grid = document.getElementById('gridDestacados');
  if (grid) {
    grid.innerHTML = '';
    idsDestacados.forEach(function(pid) {
      var p = productos.find(function(x){ return x.id === pid; });
      if (!p) return;
      var col   = p.col==='rosae' ? 'Rosae Lux' : p.col==='midnight' ? 'Midnight Sky' : '';
      var badge = p.col==='rosae' ? 'r' : p.col==='midnight' ? 'm' : '';
      var card = document.createElement('div');
      card.className = 'prod-card-home';
      card.innerHTML =
        '<div class="prod-img-home">' +
          (badge ? '<span class="prod-badge badge-'+badge+'">'+col+'</span>' : '') +
          '<img src="'+p.img+'" alt="'+p.nombre+'" style="pointer-events:none">' +
          '<div class="prod-hover-home">' +
            '<button class="btn-add" type="button">+ A&#209;ADIR AL CARRITO</button>' +
          '</div>' +
        '</div>' +
        (col ? '<p class="prod-col-tag">'+col+'</p>' : '') +
        '<h3 class="prod-nom-home">'+p.nombre+'</h3>' +
        '<p class="prod-price-home">'+p.precio.toLocaleString('es-ES')+',00 &#8364;</p>';
      // Eventos seguros sin onclick inline
      card.addEventListener('click', function() {
        window.location.href = 'catalogo.html?id=' + p.id;
      });
      var btnAdd = card.querySelector('.btn-add');
      if (btnAdd) {
        btnAdd.addEventListener('click', function(e) {
          e.stopPropagation();
          anadirCarrito(p.id);
        });
      }
      grid.appendChild(card);
    });
  }
  // Colecciones slider
  var indiceCol=0;
  var slides=['slide-midnight','slide-rosae'];
  window.irColeccion = function(i) {
    slides.forEach(function(s){ document.getElementById(s).classList.remove('on'); });
    document.querySelectorAll('.c-punto').forEach(function(p){ p.classList.remove('on'); });
    indiceCol=i;
    document.getElementById(slides[i]).classList.add('on');
    document.querySelectorAll('.c-punto')[i].classList.add('on');
  };
  setInterval(function(){ irColeccion((indiceCol+1)%slides.length); }, 6000);
});
function cerrarPopup() {
  document.getElementById('popup-overlay').style.display='none';
  sessionStorage.setItem('stellaris_popup','1');
}
function suscribirPopup() {
  var email = document.getElementById('popupEmail').value.trim();
  var privOk = document.getElementById('popupPrivacidad').checked;
  if(!email||!email.includes('@')) { toast('Introduce un correo válido.'); return; }
  if(!privOk) { toast('Debes aceptar la Política de Privacidad para continuar.'); return; }
  toast('&#10022; Bienvenida a Stellaris. ¡Gracias por suscribirte!');
  cerrarPopup();
}
/* Aqui acaban las cosas del index*/

/*Catologo*/
var filtroActual='todos', ordenActual='defecto', vistaActual=4;

function filtrarCat(filtro, event) {
  filtroActual=filtro;
  document.querySelectorAll('.f-btn').forEach(function(b){ b.classList.remove('on'); });
  if(event && event.currentTarget) event.currentTarget.classList.add('on');
  else {
    var opts=['todos','rosae','midnight','anillos','colgantes','pulseras','pendientes'];
    var idx=opts.indexOf(filtro);
    if(idx>=0) document.querySelectorAll('.f-btn')[idx] && document.querySelectorAll('.f-btn')[idx].classList.add('on');
  }
  renderCatalogo();
}
function ordenarCat() { ordenActual=document.getElementById('selectOrden').value; renderCatalogo(); }
function cambiarVista(cols) {
  vistaActual=cols;
  document.querySelectorAll('.vista-btn').forEach(function(b){ b.classList.remove('on'); });
  var vb=document.getElementById('vista-'+cols); if(vb) vb.classList.add('on');
  var grid=document.getElementById('gridCat');
  grid.className='prod-grid'+(cols===3?' v3':cols===2?' v2':'');
  renderCatalogo();
}
function renderCatalogo() {
  var lista = productos.filter(function(p) {
    if (filtroActual === 'todos') return true;
    if (filtroActual === 'rosae' || filtroActual === 'midnight') return p.col === filtroActual;
    return p.cat === filtroActual;
  });
  if (ordenActual === 'precio-asc')  lista.sort(function(a,b){ return a.precio - b.precio; });
  if (ordenActual === 'precio-desc') lista.sort(function(a,b){ return b.precio - a.precio; });
  if (ordenActual === 'nombre')      lista.sort(function(a,b){ return a.nombre.localeCompare(b.nombre); });
  var count = document.getElementById('catCount');
  if (count) count.textContent = lista.length + (lista.length === 1 ? ' pieza' : ' piezas');
  var grid = document.getElementById('gridCat');
  if (lista.length === 0) {
    grid.innerHTML = '<div class="sin-resultados"><p>No se encontraron piezas.</p><button class="btn-n" onclick="filtrarCat(\'todos\')">Ver todo</button></div>';
    return;
  }
  // Generar HTML de tarjetas
  var tarjetas = '';
  lista.forEach(function(p) {
    var col = p.col === 'rosae' ? 'Rosae Lux' : p.col === 'midnight' ? 'Midnight Sky' : '';
    var badge = p.col === 'rosae' ? 'r' : p.col === 'midnight' ? 'm' : '';
    var colClass = p.col === 'rosae' ? 'col-rosae' : p.col === 'midnight' ? 'col-midnight' : 'col-ninguna';
    var badgeHtml = badge ? '<span class="prod-badge-col badge-' + badge + '">' + col + '</span>' : '';
    var colTagHtml = col ? '<p class="prod-col-tag-cat ' + colClass + '">' + col + '</p>' : '';
    tarjetas +=
      '<div class="prod-card" data-id="' + p.id + '">' +
        '<div class="prod-img-wrap">' +
          badgeHtml +
          '<img class="img-joya" src="' + p.img + '" alt="' + p.nombre + '">' +
          '<div class="prod-acciones">' +
            '<button class="btn-ver-cat" data-id="' + p.id + '" data-accion="ver">Ver pieza</button>' +
            '<button class="btn-add-cat" data-id="' + p.id + '" data-accion="add">+ Carrito</button>' +
          '</div>' +
        '</div>' +
        colTagHtml +
        '<h3 class="prod-nombre">' + p.nombre + '</h3>' +
        '<p class="prod-precio">' + p.precio.toLocaleString('es-ES') + ',00 \u20AC</p>' +
      '</div>';
  });
  grid.innerHTML = tarjetas;
  // Eventos con data-attributes para evitar problemas con IDs string
  grid.querySelectorAll('.prod-card').forEach(function(card) {
    var id = card.getAttribute('data-id');
    card.addEventListener('click', function(e) {
      if (!e.target.closest('.prod-acciones')) abrirDetalle(id);
    });
    var btnVer = card.querySelector('[data-accion="ver"]');
    var btnAdd = card.querySelector('[data-accion="add"]');
    if (btnVer) btnVer.addEventListener('click', function(e) { e.stopPropagation(); abrirDetalle(id); });
    if (btnAdd) btnAdd.addEventListener('click', function(e) { e.stopPropagation(); anadirCarrito(id); });
  });
}

function abrirDetalle(id) {
  var p = productos.find(function(x) { return x.id === id; });
  if (!p) return;
  history.pushState({}, '', '?id=' + id);

  var esRosae    = p.col === 'rosae';
  var esMidnight = p.col === 'midnight';
  var colColor   = esRosae ? '#9b3050' : esMidnight ? '#2d4a8a' : '#1a1a1a';
  var colNombre  = esRosae ? 'Rosae Lux' : esMidnight ? 'Midnight Sky' : 'Stellaris';
  var badgeClase = esRosae ? 'badge-r' : esMidnight ? 'badge-m' : '';
  var catNombre  = p.cat.charAt(0).toUpperCase() + p.cat.slice(1);
  var tieneGaleria = p.galeria && p.galeria.length > 1;

  // Construir HTML del modal de forma segura
  var cont = document.getElementById('prod-detalle-contenido');
  cont.innerHTML = '';

  var grid = document.createElement('div');
  grid.className = 'pd-grid';

  // Panel imagen
  var panelImg = document.createElement('div');
  panelImg.className = 'pd-img';
  panelImg.style.background = 'var(--rosa-fondo)';

  if (badgeClase) {
    var badge = document.createElement('span');
    badge.className = 'pd-col-badge ' + badgeClase;
    badge.textContent = colNombre;
    panelImg.appendChild(badge);
  }

  var mainImg = document.createElement('img');
  mainImg.id = 'pd-main-img';
  mainImg.src = p.img;
  mainImg.alt = p.nombre;
  mainImg.style.cssText = 'width:100%;max-height:400px;object-fit:contain;display:block';
  panelImg.appendChild(mainImg);

  // Miniaturas de galería
  if (tieneGaleria) {
    var thumbsCont = document.createElement('div');
    thumbsCont.style.cssText = 'display:flex;gap:8px;margin-top:14px;flex-wrap:wrap;justify-content:center;padding:0 16px';
    p.galeria.forEach(function(src, i) {
      var thumb = document.createElement('div');
      thumb.style.cssText = 'width:60px;height:60px;overflow:hidden;cursor:pointer;border:2px solid ' + (i === 0 ? 'var(--negro)' : 'var(--gris-borde)') + ';flex-shrink:0;transition:border-color .2s';
      var tImg = document.createElement('img');
      tImg.src = src;
      tImg.style.cssText = 'width:100%;height:100%;object-fit:cover';
      thumb.appendChild(tImg);
      (function(s, idx, el) {
        el.addEventListener('click', function() {
          mainImg.src = s;
          thumbsCont.querySelectorAll('div').forEach(function(t, j) {
            t.style.borderColor = j === idx ? 'var(--negro)' : 'var(--gris-borde)';
          });
        });
      })(src, i, thumb);
      thumbsCont.appendChild(thumb);
    });
    panelImg.appendChild(thumbsCont);
  }

  grid.appendChild(panelImg);

  // Panel info
  var panelInfo = document.createElement('div');
  panelInfo.className = 'pd-cuerpo';

  panelInfo.innerHTML =
    '<p class="pd-eye" style="color:' + colColor + '">' + colNombre + ' \u00B7 ' + catNombre + '</p>' +
    '<h2 class="pd-nom">' + p.nombre + '</h2>' +
    '<p class="pd-precio">' + p.precio.toLocaleString('es-ES') + ',00 \u20AC</p>' +
    '<p class="pd-desc">' + p.desc + '</p>' +
    '<div class="pd-fichas">' +
      '<div><p class="pd-ficha-label">Material</p><p class="pd-ficha-valor">' + p.material + '</p></div>' +
      '<div><p class="pd-ficha-label">Piedras</p><p class="pd-ficha-valor">' + p.piedras + '</p></div>' +
      '<div><p class="pd-ficha-label">Colecci\u00F3n</p><p class="pd-ficha-valor">' + colNombre + '</p></div>' +
      '<div><p class="pd-ficha-label">Referencia</p><p class="pd-ficha-valor">' + p.referencia + '</p></div>' +
    '</div>' +
    '<p class="pd-envio">\u2736 Env\u00EDo gratuito \u00B7 Devoluci\u00F3n en 30 d\u00EDas \u00B7 Garant\u00EDa 2 a\u00F1os</p>';

  // Botones (creados con addEventListener, sin onclick inline)
  var btns = document.createElement('div');
  btns.className = 'pd-btns';

  var btnAnyadir = document.createElement('button');
  btnAnyadir.className = 'btn-add-det';
  btnAnyadir.textContent = 'A\u00D1ADIR AL CARRITO';
  btnAnyadir.addEventListener('click', function() { anadirCarrito(p.id); });

  var btnPreguntar = document.createElement('button');
  btnPreguntar.className = 'btn-cta-det';
  btnPreguntar.textContent = 'PREGUNTAR POR ESTA PIEZA';
  btnPreguntar.addEventListener('click', function() { cerrarModalProducto(); abrirContacto(); });

  btns.appendChild(btnAnyadir);
  btns.appendChild(btnPreguntar);
  panelInfo.appendChild(btns);

  var nota = document.createElement('p');
  nota.className = 'pd-envio';
  nota.textContent = '\u2736 Env\u00EDo gratuito \u00B7 Devoluci\u00F3n en 30 d\u00EDas \u00B7 Garant\u00EDa 2 a\u00F1os';
  // (ya incluida en innerHTML arriba, no añadir dos veces)

  grid.appendChild(panelInfo);
  cont.appendChild(grid);

  document.getElementById('modal-producto').classList.add('on');
  document.getElementById('overlay').classList.add('on');
  document.body.style.overflow = 'hidden';
}

function cerrarModalProducto() {
  document.getElementById('modal-producto').classList.remove('on');
  document.getElementById('overlay').classList.remove('on');
  document.body.style.overflow='';
  history.pushState({},'',window.location.pathname+(filtroActual!=='todos'?'?col='+filtroActual:''));
}
function leerURLParams() {
  var params=new URLSearchParams(window.location.search);
  var col=params.get('col');
  var id=params.get('id');
  if(col){ filtroActual=col; filtrarCat(col); }
  else renderCatalogo();
  if(id) setTimeout(function(){ abrirDetalle(id); },300);
}
function cerrarOverlayCat() {
  if(document.getElementById('modal-producto').classList.contains('on')){ cerrarModalProducto(); return; }
  cerrarModales();
}


function rehidratarCarrito() {
  try {
    var guardado = JSON.parse(localStorage.getItem('stellaris_carrito') || '[]');
    carrito = guardado.map(function(item) {
      // Reconstituir img desde el array productos
      var prod = productos.find(function(p){ return p.id === item.id; });
      return {
        id: item.id,
        nombre: item.nombre,
        precio: item.precio,
        col: item.col,
        cat: item.cat,
        cantidad: item.cantidad,
        img: prod ? prod.img : null
      };
    });
  } catch(e) {
    carrito = [];
  }
}
document.addEventListener('DOMContentLoaded', function() {
  initBanner();
  rehidratarCarrito();
  renderizarCarrito();
  actualizarUsr();
  leerURLParams();
  // Limpiar localStorage viejo con datos base64 si existía
  try {
    var guardado = JSON.parse(localStorage.getItem('stellaris_carrito') || '[]');
    if(guardado.length > 0 && guardado[0].img && guardado[0].img.startsWith('data:')) {
      localStorage.removeItem('stellaris_carrito');
      carrito = [];
      renderizarCarrito();
    }
  } catch(e) {}
});
